function updateFormula(step){
const formulaHtml = step.formulaHtml || `<div class="formula-line">${step.formula}</div>`
const bannerHtml = step.bannerHtml || `<span class="eq-main">${step.formula}</span>`
formulaCard.innerHTML = `<strong>${step.formulaTitle}</strong>${formulaHtml}<div>Nesta etapa, a fórmula funciona como guia de leitura histórica e conceitual do modelo ou do experimento em foco.</div>`
equationBanner.innerHTML = bannerHtml
}

function updateStep(){
beginSceneTransition()
const step = steps[state.step]
state.quantumFocus = null
state.quantumHitRegions = []
guideKicker.textContent = step.kicker
guideHeading.textContent = step.title
guideText.innerHTML = step.text.map((paragraph) => `<p>${paragraph}</p>`).join('')
guideCallout.textContent = step.callout

tutorialStepTag.textContent = `Passo ${state.step + 1} / ${steps.length}`
tutorialPrev.disabled = state.step === 0
tutorialNext.disabled = state.step === steps.length - 1
updateOverlay(step.chips)
updateFormula(step)
hudScene.textContent = step.kicker
hudCount.textContent = step.scene === 'schrodinger' ? 'equação de Schrödinger' : 'linha histórica'
hudEnergy.textContent = step.scene === 'schrodinger' ? 'ψ = R · Y' : 'de Dalton a Schrödinger'
stepButtons.forEach((button, index) => button.classList.toggle('active', index === state.step))
}

function orbitalLabel(){
const meta = orbitalMetaFromState()
if(meta) return meta.label
const labels = ['s','p','d','f','g']
return `${state.orbital.n}${labels[state.orbital.l] || '?'} (m=${state.orbital.m})`
}

function updateOrbitalPanel(){
const energy = energyEV(state.orbital.Z, state.orbital.n)
const advancedVisible = hydrogenSceneActive()
const section = document.getElementById('hydrogenoidSection')
section.style.opacity = advancedVisible ? '1' : '.78'
section.style.filter = advancedVisible ? 'none' : 'saturate(.75)'
speciesTag.textContent = speciesMap[state.orbital.Z]
if(orbitalAtlasTag) orbitalAtlasTag.textContent = state.orbitalView === '3d' ? 'orbital 3D' : 'corte analítico'
syncOrbitalViewButtons()
const radialNodes = radialNodeCount(state.orbital.n, state.orbital.l)
const angularNodes = angularNodeCount(state.orbital.l)
const bohrRadius = (state.orbital.n * state.orbital.n) / state.orbital.Z
statsGrid.innerHTML = `
<div class="stat-card"><div class="label">Estado</div><div class="value">${orbitalLabel()}</div></div>
<div class="stat-card"><div class="label">Energia</div><div class="value">${energy.toFixed(3)} eV</div></div>
<div class="stat-card"><div class="label">Nós radiais</div><div class="value">${radialNodes}</div></div>
<div class="stat-card"><div class="label">Nós angulares</div><div class="value">${angularNodes}</div></div>
<div class="stat-card"><div class="label">Escala radial típica</div><div class="value">${bohrRadius.toFixed(2)} a₀</div></div>
<div class="stat-card"><div class="label">Íon</div><div class="value">${speciesMap[state.orbital.Z]}</div></div>
`
orbitalNote.innerHTML = state.orbitalView === '3d' ? `No modo <strong>orbital 3D</strong>, a cena principal mostra a densidade tridimensional <strong>|ψ|²</strong> do estado selecionado, permitindo girar a distribuição espacial do orbital. A galeria abaixo continua servindo como atlas de referência dos estados do hidrogênio. Aumentar <strong>Z</strong> comprime a nuvem; aumentar <strong>n</strong> tende a expandi-la.` : `No estado selecionado, a energia segue <strong>E<sub>n</sub> ∝ -Z²/n²</strong>, enquanto a forma espacial emerge da combinação entre <strong>l</strong> e <strong>m</strong> na função <strong>ψ<sub>n,l,m</sub>(r,θ,φ)</strong>. A galeria abaixo agora reúne todos os orbitais do lote do hidrogênio entre n = 1 e n = 5, com cortes analíticos vindos do lote real enviado em .npz e passo dedicado para cada estado. Aumentar <strong>Z</strong> comprime a nuvem; aumentar <strong>n</strong> tende a expandi-la.`
buildOrbitalAtlas()
drawRadialGraph()
}

function drawRadialGraph(){
const width = radialGraph.width
const height = radialGraph.height
radialCtx.clearRect(0,0,width,height)
const grd = radialCtx.createLinearGradient(0,0,0,height)
grd.addColorStop(0,'#0c1730')
grd.addColorStop(1,'#07101b')
radialCtx.fillStyle = grd
radialCtx.fillRect(0,0,width,height)
radialCtx.strokeStyle = 'rgba(150,190,255,.16)'
radialCtx.lineWidth = 1
for(let i = 0; i < 5; i += 1){
const y = 18 + i * (height - 36) / 4
radialCtx.beginPath()
radialCtx.moveTo(18,y)
radialCtx.lineTo(width - 12,y)
radialCtx.stroke()
}
const rMax = Math.max(5, 8 * state.orbital.n * state.orbital.n / state.orbital.Z)
const points = []
let max = 0
for(let i = 0; i < 180; i += 1){
const r = rMax * i / 179
const radial = radialHydrogenic(state.orbital.n, state.orbital.l, state.orbital.Z, r)
const value = r * r * radial * radial
points.push({r,value})
if(value > max) max = value
}
radialCtx.beginPath()
points.forEach((point, index) => {
const x = 18 + (width - 30) * point.r / rMax
const y = height - 18 - (height - 36) * (point.value / (max || 1))
if(index === 0) radialCtx.moveTo(x,y)
else radialCtx.lineTo(x,y)
})
radialCtx.strokeStyle = '#87e9ff'
radialCtx.lineWidth = 2.4
radialCtx.stroke()
radialCtx.lineTo(width - 12, height - 18)
radialCtx.lineTo(18, height - 18)
radialCtx.closePath()
const fill = radialCtx.createLinearGradient(0,18,0,height)
fill.addColorStop(0,'rgba(110,125,255,.42)')
fill.addColorStop(1,'rgba(118,209,255,.02)')
radialCtx.fillStyle = fill
radialCtx.fill()
radialCtx.fillStyle = 'rgba(236,243,255,.88)'
radialCtx.font = '12px Inter, system-ui, sans-serif'
radialCtx.fillText('P(r) = r²|R(r)|²', 18, 14)
radialCtx.fillStyle = 'rgba(160,184,220,.88)'
radialCtx.fillText('r', width - 18, height - 4)
}

function resizeCanvas(){
const rect = canvas.getBoundingClientRect()
canvas.width = Math.max(500, Math.floor(rect.width * devicePixelRatio))
canvas.height = Math.max(380, Math.floor(rect.height * devicePixelRatio))
ctx.setTransform(devicePixelRatio,0,0,devicePixelRatio,0,0)
}

function rotatePoint(x, y, z){
const cy = Math.cos(state.yaw)
const sy = Math.sin(state.yaw)
const cp = Math.cos(state.pitch)
const sp = Math.sin(state.pitch)

const xYaw = x * cy - z * sy
const zYaw = x * sy + z * cy
const yPitch = y * cp - zYaw * sp
const zPitch = y * sp + zYaw * cp

return {x:xYaw, y:yPitch, z:zPitch}
}

function projectPoint(x, y, z, extent = 7){
const rotated = rotatePoint(x, y, z)
const viewWidth = canvas.width / devicePixelRatio
const viewHeight = canvas.height / devicePixelRatio
const scaleBase = Math.min(viewWidth, viewHeight) * 0.5 / extent
const orthoScale = scaleBase * state.zoom
return {
x: viewWidth * 0.5 + rotated.x * orthoScale,
y: viewHeight * 0.5 - rotated.y * orthoScale,
size: orthoScale,
z: rotated.z
}
}
function sceneOrthoScale(extent = 7){
const viewWidth = canvas.width / devicePixelRatio
const viewHeight = canvas.height / devicePixelRatio
return Math.min(viewWidth, viewHeight) * 0.5 / extent * state.zoom
}

function drawBackground(time){
const w = canvas.width / devicePixelRatio
const h = canvas.height / devicePixelRatio
const gradient = ctx.createLinearGradient(0,0,0,h)
gradient.addColorStop(0,'#091221')
gradient.addColorStop(.55,'#08111d')
gradient.addColorStop(1,'#050910')
ctx.fillStyle = gradient
ctx.fillRect(0,0,w,h)
for(let i = 0; i < 70; i += 1){
const x = (i * 97.13) % w
const y = (i * 173.47 + time * 0.004 * (i % 3 + 1)) % h
const alpha = 0.07 + 0.08 * ((i % 7) / 6)
ctx.fillStyle = `rgba(190,220,255,${alpha})`
ctx.beginPath()
ctx.arc(x, y, 1.1 + (i % 3) * 0.35, 0, Math.PI * 2)
ctx.fill()
}
}

function drawAxes(extent){
if(!showAxesControl.checked) return
const colors = [
{vec:[extent,0,0], label:'x', color:'#7fd4ff'},
{vec:[0,extent,0], label:'y', color:'#8ee144'},
{vec:[0,0,extent], label:'z', color:'#b68cff'}
]
colors.forEach((item) => {
const a = projectPoint(0,0,0,extent)
const b = projectPoint(item.vec[0],item.vec[1],item.vec[2],extent)
ctx.strokeStyle = item.color
ctx.lineWidth = 1.4
ctx.beginPath()
ctx.moveTo(a.x,a.y)
ctx.lineTo(b.x,b.y)
ctx.stroke()
if(showLabelsControl.checked){
ctx.fillStyle = item.color
ctx.font = '12px Inter, system-ui, sans-serif'
ctx.fillText(item.label, b.x + 6, b.y - 6)
}
})
}


const cloudSpriteCache = new Map()

function rgbaColor(rgb, alpha){
return `rgba(${rgb[0]},${rgb[1]},${rgb[2]},${alpha})`
}

function getPointSprite(rgb = [255,255,255], type = 'dot'){
const key = `${type}_${rgb.join('_')}`
if(cloudSpriteCache.has(key)) return cloudSpriteCache.get(key)
const c = document.createElement('canvas')
const size = type === 'halo' ? 72 : type === 'soft' ? 40 : 24
c.width = size
c.height = size
const g = c.getContext('2d')
const grad = g.createRadialGradient(size * 0.5, size * 0.5, size * 0.02, size * 0.5, size * 0.5, size * 0.5)
if(type === 'halo'){
grad.addColorStop(0.00, rgbaColor(rgb, 0.24))
grad.addColorStop(0.34, rgbaColor(rgb, 0.12))
grad.addColorStop(1.00, rgbaColor(rgb, 0))
}else if(type === 'soft'){
grad.addColorStop(0.00, 'rgba(255,255,255,0.96)')
grad.addColorStop(0.16, rgbaColor(rgb, 0.78))
grad.addColorStop(0.54, rgbaColor(rgb, 0.20))
grad.addColorStop(1.00, rgbaColor(rgb, 0))
}else{
grad.addColorStop(0.00, 'rgba(255,255,255,1)')
grad.addColorStop(0.16, 'rgba(255,255,255,0.98)')
grad.addColorStop(0.46, rgbaColor(rgb, 0.88))
grad.addColorStop(0.84, rgbaColor(rgb, 0.08))
grad.addColorStop(1.00, rgbaColor(rgb, 0))
}
g.fillStyle = grad
g.fillRect(0, 0, size, size)
cloudSpriteCache.set(key, c)
return c
}

function orbitalDisplayPalette(n, l){
if(n % 2 === 0){
return {
base:[92,188,255],
halo:[47,136,232],
spark:[232,247,255],
accent:[194,234,255]
}
}
return {
base:[255,170,86],
halo:[255,121,34],
spark:[255,238,214],
accent:[255,210,140]
}
}

function normalizePaletteInput(colorA = [255,255,255], colorB = [255,255,255]){
const base = Array.isArray(colorA) ? colorA : [255,255,255]
const halo = Array.isArray(colorB) ? colorB : base
return {base, halo, spark:[255,255,255], accent:halo}
}

function drawVolumetricCloud(points, extent, pointSize = 1, palette = null){
const projected = []
for(let i = 0; i < points.length; i += 1){
const point = points[i]
const proj = projectPoint(point.x, point.y, point.z, extent)
projected.push({point, proj})
}
projected.sort((a,b) => a.proj.z - b.proj.z)
const activePalette = palette || {base:[255,255,255], halo:[255,255,255], spark:[255,255,255], accent:[255,255,255]}
const haloSprite = getPointSprite(activePalette.halo, 'halo')
const softSprite = getPointSprite(activePalette.base, 'soft')
const dotSprite = getPointSprite(activePalette.base, 'dot')
const stride = projected.length > 2500 ? 2 : 1
ctx.save()
ctx.globalCompositeOperation = 'lighter'
for(let i = 0; i < projected.length; i += stride){
const item = projected[i]
const point = item.point
const proj = item.proj
const density = point.density ?? 0.4
const alpha = Math.max(0.018, Math.min(0.26, (point.alpha ?? 0.12) * (0.62 + 0.58 * Math.pow(1 - (point.radialFraction ?? 0.5), 0.42))))
const scale = pointSize * proj.size * (0.78 + 0.34 * (point.renderScale ?? 1))
if(i % 4 === 0){
const haloRadius = Math.max(1.6, scale * (1.9 + 0.42 * (point.glow ?? 1)))
ctx.globalAlpha = alpha * 0.34
ctx.drawImage(haloSprite, proj.x - haloRadius, proj.y - haloRadius, haloRadius * 2, haloRadius * 2)
}
const softRadius = Math.max(0.9, scale * (0.82 + density * 0.54))
ctx.globalAlpha = alpha * (0.64 + density * 0.42)
ctx.drawImage(softSprite, proj.x - softRadius, proj.y - softRadius, softRadius * 2, softRadius * 2)
const dotRadius = Math.max(0.58, scale * (0.42 + density * 0.18))
ctx.globalAlpha = Math.min(0.82, alpha * (1.10 + density * 0.92))
ctx.drawImage(dotSprite, proj.x - dotRadius, proj.y - dotRadius, dotRadius * 2, dotRadius * 2)
}
ctx.restore()
}

function drawSphereCloud(points, extent, colorA, colorB, pointSize = 1){
drawVolumetricCloud(points, extent, pointSize, normalizePaletteInput(colorA, colorB))
}

function drawGlossSphere(extent, modelRadius, palette){
const center = projectPoint(0,0,0,extent)
const radius = Math.max(42, center.size * modelRadius)
const lightX = center.x - radius * 0.34
const lightY = center.y - radius * 0.42
const body = ctx.createRadialGradient(lightX, lightY, radius * 0.10, center.x, center.y, radius)
body.addColorStop(0, palette.highlight)
body.addColorStop(0.28, palette.mid)
body.addColorStop(0.70, palette.base)
body.addColorStop(1, palette.rim)
ctx.save()
ctx.shadowColor = 'rgba(0,0,0,.32)'
ctx.shadowBlur = radius * 0.22
ctx.fillStyle = body
ctx.beginPath()
ctx.arc(center.x, center.y, radius, 0, Math.PI * 2)
ctx.fill()
ctx.shadowBlur = 0
const rim = ctx.createRadialGradient(center.x, center.y, radius * 0.35, center.x, center.y, radius * 1.1)
rim.addColorStop(0, 'rgba(255,255,255,0)')
rim.addColorStop(0.75, 'rgba(255,255,255,0)')
rim.addColorStop(1, 'rgba(255,255,255,.15)')
ctx.fillStyle = rim
ctx.beginPath()
ctx.arc(center.x, center.y, radius, 0, Math.PI * 2)
ctx.fill()
ctx.restore()
return {center, radius}
}

function drawDaltonModel(extent){
const sphere = drawGlossSphere(extent, 3.2, {
base:'#4e5055',
mid:'#70747c',
rim:'#1c1f25',
highlight:'rgba(255,255,255,.92)'
})
drawSphereSurfaceMarks(sceneCache.daltonShell, extent, {
colors:['rgba(255,255,255,.14)','rgba(35,39,47,.30)','rgba(255,255,255,.08)'],
backCutoff:0.04,
baseSize:0.010,
ellipticity:0.84
})
ctx.strokeStyle = 'rgba(255,255,255,.09)'
ctx.lineWidth = 1.2
ctx.beginPath()
ctx.arc(sphere.center.x, sphere.center.y, sphere.radius * 0.98, 0, Math.PI * 2)
ctx.stroke()
}

function drawPanettoneModel(extent){
const sphere = drawGlossSphere(extent, 3.28, {
base:'#a95f11',
mid:'#ee9b2d',
rim:'#6c3608',
highlight:'rgba(255,244,194,.98)'
})
ctx.save()
ctx.globalAlpha = 0.2
ctx.fillStyle = 'rgba(255,202,102,.48)'
ctx.beginPath()
ctx.arc(sphere.center.x, sphere.center.y, sphere.radius * 0.98, 0, Math.PI * 2)
ctx.fill()
ctx.restore()

drawSphereSurfaceMarks(sceneCache.thomsonShell, extent, {
colors:['rgba(255,236,196,.16)','rgba(156,87,26,.20)','rgba(255,202,124,.10)'],
backCutoff:0.06,
baseSize:0.009,
ellipticity:0.8
})

ctx.strokeStyle = 'rgba(255,244,214,.24)'
ctx.lineWidth = 1.2
ctx.beginPath()
ctx.arc(sphere.center.x, sphere.center.y, sphere.radius * 0.985, 0, Math.PI * 2)
ctx.stroke()

ctx.save()
ctx.textAlign = 'center'
ctx.textBaseline = 'middle'
ctx.fillStyle = 'rgba(255,246,226,.88)'
ctx.strokeStyle = 'rgba(120,56,10,.38)'
ctx.lineWidth = Math.max(1.4, sphere.radius * 0.025)
ctx.font = `700 ${Math.max(26, sphere.radius * 0.34)}px Inter, system-ui, sans-serif`
ctx.strokeText('+', sphere.center.x, sphere.center.y)
ctx.fillText('+', sphere.center.x, sphere.center.y)
ctx.restore()

sceneCache.thomsonElectrons
.map((item, index) => {
const rotated = rotatePoint(item.x, item.y, item.z)
return {item, index, depth: rotated.z}
})
.filter(({depth}) => depth >= 0.02)
.sort((a, b) => a.depth - b.depth)
.forEach(({item, index, depth}) => {
const p = projectPoint(item.x, item.y, item.z, extent)
const visibility = 0.72 + Math.min(1, depth / 2.5) * 0.28
const electronRadius = Math.max(12, p.size * 0.042 * visibility)
const electronHalo = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, electronRadius * 2.8)
electronHalo.addColorStop(0, 'rgba(255,208,208,.42)')
electronHalo.addColorStop(0.45, 'rgba(255,94,94,.20)')
electronHalo.addColorStop(1, 'rgba(255,94,94,0)')
ctx.fillStyle = electronHalo
ctx.beginPath()
ctx.arc(p.x, p.y, electronRadius * 2.8, 0, Math.PI * 2)
ctx.fill()

const electronFill = index % 2 === 0 ? 'rgba(236,56,56,.98)' : 'rgba(206,32,44,.98)'
ctx.fillStyle = electronFill
ctx.beginPath()
ctx.arc(p.x, p.y, electronRadius, 0, Math.PI * 2)
ctx.fill()

ctx.strokeStyle = 'rgba(255,230,230,.55)'
ctx.lineWidth = 1.1
ctx.beginPath()
ctx.arc(p.x, p.y, electronRadius * 1.02, 0, Math.PI * 2)
ctx.stroke()

ctx.save()
ctx.textAlign = 'center'
ctx.textBaseline = 'middle'
ctx.fillStyle = 'rgba(255,245,245,.98)'
ctx.font = `800 ${Math.max(13, electronRadius * 1.05)}px Inter, system-ui, sans-serif`
ctx.fillText('−', p.x, p.y + electronRadius * 0.02)
ctx.restore()
})
}

function drawFieldArrow3D(x, yTop, yBottom, z, extent){
const a = projectPoint(x, yTop, z, extent)
const b = projectPoint(x, yBottom, z, extent)
ctx.strokeStyle = 'rgba(173,204,255,.32)'
ctx.lineWidth = 1.1
ctx.beginPath()
ctx.moveTo(a.x, a.y)
ctx.lineTo(b.x, b.y)
ctx.stroke()
ctx.beginPath()
ctx.moveTo(b.x, b.y)
ctx.lineTo(b.x - 4, b.y - 8)
ctx.lineTo(b.x + 4, b.y - 8)
ctx.closePath()
ctx.fillStyle = 'rgba(173,204,255,.32)'
ctx.fill()
}

function buildSolidSphere(radius, count){
const points = []
for(let i = 0; i < count; i += 1){
const u = Math.random()
const v = Math.random()
const theta = 2 * Math.PI * u
const phi = Math.acos(2 * v - 1)
const r = radius * Math.cbrt(Math.random())
points.push({
x:r * Math.sin(phi) * Math.cos(theta),
y:r * Math.sin(phi) * Math.sin(theta),
z:r * Math.cos(phi),
alpha:.5 + Math.random() * .3,
renderScale:0.9 + Math.random() * .6,
sign:1
})
}
return points
}

function buildSurfaceShell(radius, count, jitter = 0.0){
const points = []
for(let i = 0; i < count; i += 1){
const u = Math.random()
const v = Math.random()
const theta = 2 * Math.PI * u
const phi = Math.acos(2 * v - 1)
const r = radius * (1 + (Math.random() - 0.5) * jitter)
points.push({
x:r * Math.sin(phi) * Math.cos(theta),
y:r * Math.sin(phi) * Math.sin(theta),
z:r * Math.cos(phi),
size:0.75 + Math.random() * 1.35,
alpha:0.18 + Math.random() * 0.22,
tilt:(Math.random() - 0.5) * 0.9
})
}
return points
}

function drawSphereSurfaceMarks(points, extent, styles = {}){
const colors = styles.colors || ['rgba(255,255,255,.16)']
const backCutoff = styles.backCutoff ?? 0.05
const baseSize = styles.baseSize ?? 0.012
const ellipticity = styles.ellipticity ?? 0.78
const withStroke = styles.withStroke ?? false
const strokeStyle = styles.strokeStyle || 'rgba(255,255,255,.08)'
const projected = []
for(let i = 0; i < points.length; i += 1){
const point = points[i]
const rotated = rotatePoint(point.x, point.y, point.z)
if(rotated.z < backCutoff) continue
projected.push({point, rotated, proj:projectPoint(point.x, point.y, point.z, extent)})
}
projected.sort((a,b) => a.rotated.z - b.rotated.z)
ctx.save()
for(let i = 0; i < projected.length; i += 1){
const item = projected[i]
const depth = Math.max(0, Math.min(1, item.rotated.z / 3.4))
const radius = Math.max(1.0, item.proj.size * baseSize * item.point.size * (0.72 + depth * 0.75))
const alpha = Math.max(0.06, Math.min(0.44, item.point.alpha * (0.70 + depth * 0.75)))
ctx.fillStyle = colors[i % colors.length]
ctx.globalAlpha = alpha
ctx.beginPath()
ctx.ellipse(item.proj.x, item.proj.y, radius, radius * ellipticity, item.point.tilt, 0, Math.PI * 2)
ctx.fill()
if(withStroke){
ctx.globalAlpha = Math.min(0.22, alpha * 0.7)
ctx.strokeStyle = strokeStyle
ctx.lineWidth = 0.6
ctx.stroke()
}
}
ctx.restore()
}

function halton(index, base){
let result = 0
let f = 1 / base
let i = index + 1
while(i > 0){
result += f * (i % base)
i = Math.floor(i / base)
f /= base
}
return result
}

function softNoise(index, offset = 0){
const x = Math.sin((index + 1) * 127.1 + offset * 311.7) * 43758.5453123
return x - Math.floor(x)
}

function gaussianFromSequence(index, baseA, baseB){
const u1 = Math.max(1e-6, halton(index * 2 + 1, baseA))
const u2 = Math.max(1e-6, halton(index * 2 + 2, baseB))
return Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2)
}

function buildGaussianCloud(count, spread){
const points = []
let i = 0
const limit = count * 8
while(points.length < count && i < limit){
i += 1
const x = gaussianFromSequence(i + 11, 2, 3) * spread * 0.88
const y = gaussianFromSequence(i + 37, 5, 7) * spread * 0.82
const z = gaussianFromSequence(i + 73, 11, 13) * spread * 0.88
const r = Math.sqrt(x * x + y * y + z * z)
if(r > spread * 3.0) continue
const dense = Math.exp(-0.5 * Math.pow(r / Math.max(0.55, spread * 0.95), 2))
const alpha = 0.05 + 0.26 * dense
const renderScale = 0.95 + 2.8 * Math.pow(dense, 0.55)
const glow = 0.65 + 1.15 * Math.pow(dense, 0.36)
points.push({x, y, z, alpha, renderScale, glow, sign:1})
if(points.length < count){
const jitter = 0.03 * (softNoise(i, 1) - 0.5)
points.push({
x:-x * (1 + jitter),
y:-y * (1 - jitter),
z:-z,
alpha:alpha * 0.96,
renderScale:renderScale * 0.98,
glow,
sign:1
})
}
}
return points.slice(0, count)
}

