function drawNucleus(size, extent, color = '#ffe29f'){
const p = projectPoint(0,0,0,extent)
const glow = ctx.createRadialGradient(p.x,p.y,1,p.x,p.y,p.size * .34)
glow.addColorStop(0,'rgba(255,241,189,.95)')
glow.addColorStop(.55,'rgba(255,183,82,.65)')
glow.addColorStop(1,'rgba(255,183,82,0)')
ctx.fillStyle = glow
ctx.beginPath()
ctx.arc(p.x,p.y,p.size * .34,0,Math.PI * 2)
ctx.fill()
ctx.fillStyle = color
ctx.beginPath()
ctx.arc(p.x,p.y,Math.max(4,size * p.size * .05),0,Math.PI * 2)
ctx.fill()
}

function drawOrbitalRings(count, extent, elliptical = false, standing = false){
for(let ring = 1; ring <= count; ring += 1){
ctx.beginPath()
for(let i = 0; i <= 220; i += 1){
const t = Math.PI * 2 * i / 220
const a = 1.2 + ring * 1.05
const b = elliptical ? a * (0.62 + ring * 0.03) : a
const wave = standing ? 1 + 0.12 * Math.sin(t * ring * 8 + performance.now() * 0.004) : 1
const x = a * Math.cos(t) * wave
const y = 0.28 * Math.sin(t * 2 + ring)
const z = b * Math.sin(t) * wave
const p = projectPoint(x, y, z, extent)
if(i === 0) ctx.moveTo(p.x, p.y)
else ctx.lineTo(p.x, p.y)
}
ctx.strokeStyle = standing ? `rgba(126,226,255,${0.38 + ring * 0.06})` : `rgba(130,172,235,${0.26 + ring * 0.08})`
ctx.lineWidth = 1.2
ctx.stroke()
}
}

function drawElectronOnRing(radius, speed, phase, extent, elliptical = false, color = '#8fe6ff'){
const t = performance.now() * 0.001 * speed + phase
const a = radius
const b = elliptical ? radius * 0.68 : radius
const x = a * Math.cos(t)
const y = 0.25 * Math.sin(t * 2 + phase)
const z = b * Math.sin(t)
const p = projectPoint(x,y,z,extent)
ctx.fillStyle = color
ctx.beginPath()
ctx.arc(p.x,p.y,Math.max(3,p.size * .085),0,Math.PI * 2)
ctx.fill()
if(showTrailsControl.checked){
ctx.strokeStyle = color === '#ff5d5d' ? 'rgba(255,93,93,.16)' : 'rgba(143,230,255,.14)'
ctx.lineWidth = 1
ctx.beginPath()
ctx.arc(p.x,p.y,Math.max(7,p.size * .16),0,Math.PI * 2)
ctx.stroke()
}
}

function drawTimelineArcs(extent){
const offsets = [-5.2,-2.2,1.2,4.4]
offsets.forEach((offset, index) => {
ctx.beginPath()
for(let i = 0; i <= 70; i += 1){
const t = Math.PI * i / 70
const x = offset + Math.cos(t) * 1.4
const y = 3.2 - Math.sin(t) * 0.9
const z = Math.sin(t * 2 + index) * 0.35
const p = projectPoint(x,y,z,extent)
if(i === 0) ctx.moveTo(p.x,p.y)
else ctx.lineTo(p.x,p.y)
}
ctx.strokeStyle = 'rgba(118,209,255,.32)'
ctx.lineWidth = 1.4
ctx.stroke()
})
}

function drawRutherfordScattering(extent, time){
const particles = 24
for(let i = 0; i < particles; i += 1){
const base = ((time * 0.002) + i / particles) % 1
let x = -7 + base * 14
let y = (i % 6 - 2.5) * .75
let z = (Math.floor(i / 6) - 1.5) * .8
if(Math.abs(x) < 1.4){
const influence = 1.4 - Math.abs(x)
y += Math.sign(y || 1) * influence * influence * 1.1
z += Math.sign(z || 1) * influence * .7
}
const p = projectPoint(x,y,z,extent)
ctx.fillStyle = 'rgba(255,210,133,.85)'
ctx.beginPath()
ctx.arc(p.x,p.y,Math.max(2.2,p.size * .07),0,Math.PI * 2)
ctx.fill()
if(showTrailsControl.checked){
ctx.strokeStyle = 'rgba(255,210,133,.18)'
ctx.beginPath()
ctx.moveTo(p.x - 16, p.y)
ctx.lineTo(p.x + 8, p.y)
ctx.stroke()
}
}
}

function drawBohrTransition(extent, time){
drawOrbitalRings(3, extent, false, false)
drawElectronOnRing(2.25, 1.3, 0, extent, false)
drawElectronOnRing(3.3, .84, 1.5, extent, false)
const t = (Math.sin(time * 0.0022) + 1) * .5
const x = 3.3 * (1 - t) + 2.25 * t
const z = 0
const p = projectPoint(x, 0.15 * Math.sin(time * .004), z, extent)
ctx.fillStyle = '#f9f6ff'
ctx.beginPath()
ctx.arc(p.x,p.y,Math.max(3.2,p.size * .085),0,Math.PI * 2)
ctx.fill()
const beamColors = ['#7dd3ff','#86efac','#facc15','#fb7185']
beamColors.forEach((color, index) => {
ctx.strokeStyle = color
ctx.lineWidth = 2.4
ctx.beginPath()
ctx.moveTo(canvas.width / devicePixelRatio * .72, 52 + index * 16)
ctx.lineTo(canvas.width / devicePixelRatio * .92, 52 + index * 16)
ctx.stroke()
})
}

function drawEmissionSpectrumBand(label, y, lines, bandHeight = 44, time = 0){
const w = canvas.width / devicePixelRatio
const panelX = 46
const panelW = Math.min(430, w - 92)
ctx.fillStyle = 'rgba(0,0,0,.88)'
ctx.fillRect(panelX, y, panelW, bandHeight)
lines.forEach((line, lineIndex) => {
  const x = panelX + line.x * panelW
  const grad = ctx.createLinearGradient(0, y, 0, y + bandHeight)
  grad.addColorStop(0, 'rgba(255,255,255,0)')
  grad.addColorStop(0.30, line.color)
  grad.addColorStop(0.70, line.color)
  grad.addColorStop(1, 'rgba(255,255,255,0)')
  ctx.strokeStyle = grad
  ctx.lineWidth = line.width || 2.2
  ctx.beginPath()
  ctx.moveTo(x, y + 2)
  ctx.lineTo(x, y + bandHeight - 2)
  ctx.stroke()
  const travel = (time * 0.00018 + lineIndex * 0.13) % 1
  const pulseY = y + 6 + travel * Math.max(6, bandHeight - 12)
  const pulse = ctx.createRadialGradient(x, pulseY, 0, x, pulseY, 16)
  pulse.addColorStop(0, line.color.replace('0.95', '0.95'))
  pulse.addColorStop(0.45, line.color.replace('0.95', '0.34'))
  pulse.addColorStop(1, 'rgba(255,255,255,0)')
  ctx.fillStyle = pulse
  ctx.beginPath()
  ctx.arc(x, pulseY, 16, 0, Math.PI * 2)
  ctx.fill()
  ctx.strokeStyle = line.color
  ctx.lineWidth = 1.1
  ctx.beginPath()
  ctx.moveTo(x - 5, pulseY)
  ctx.lineTo(x + 5, pulseY)
  ctx.stroke()
})
ctx.fillStyle = 'rgba(255,255,255,.96)'
ctx.font = '700 15px Inter, system-ui, sans-serif'
ctx.textAlign = 'left'
ctx.fillText(label, panelX, y + bandHeight + 18)
}

