const stackX = innerX + 24
const stackW = innerW * 0.56
const rowGap = 28
const barH = 42
const firstY = innerY + 34
rows.forEach((row, index) => {
  const y = firstY + index * (barH + rowGap)
  ctx.save()
  ctx.fillStyle = 'rgba(0,0,0,0.94)'
  ctx.fillRect(stackX, y, stackW, barH)
  ctx.strokeStyle = 'rgba(255,255,255,0.16)'
  ctx.lineWidth = 1
  ctx.strokeRect(stackX, y, stackW, barH)
  row.lines.forEach((line, lineIndex) => {
    const lx = stackX + line.x * stackW
    const alpha = 0.72 + 0.28 * Math.sin(time * 0.002 + index * 0.7 + lineIndex * 0.45)
    ctx.save()
    ctx.shadowBlur = 9
    ctx.shadowColor = line.color.replace('0.95', '0.75')
    ctx.strokeStyle = line.color.replace('0.95', alpha.toFixed(2))
    ctx.lineWidth = line.w
    ctx.beginPath()
    ctx.moveTo(lx, y + 3)
    ctx.lineTo(lx, y + barH - 3)
    ctx.stroke()
    ctx.restore()
  })
  ctx.restore()
  ctx.save()
  ctx.fillStyle = 'rgba(246,248,255,0.96)'
  ctx.font = '700 14px Inter, system-ui, sans-serif'
  ctx.textAlign = 'left'
  ctx.fillText(row.label, stackX, y + barH + 17)
  ctx.restore()
})

const atomCx = innerX + innerW * 0.79
const atomCy = innerY + innerH * 0.62
const rxBase = Math.min(innerW, innerH) * 0.12
const ryBase = rxBase * 0.56
const atomPulse = 0.88 + 0.12 * Math.sin(time * 0.0032)
ctx.save()
const atomGlow = ctx.createRadialGradient(atomCx, atomCy, 0, atomCx, atomCy, rxBase * 2.4)
atomGlow.addColorStop(0, 'rgba(160,255,180,0.18)')
atomGlow.addColorStop(1, 'rgba(160,255,180,0)')
ctx.fillStyle = atomGlow
ctx.beginPath()
ctx.arc(atomCx, atomCy, rxBase * 2.4, 0, Math.PI * 2)
ctx.fill()
ctx.restore()

for(let ring = 0; ring < 4; ring += 1){
  const rx = rxBase * (1.1 + ring * 0.52)
  const ry = ryBase * (1.1 + ring * 0.50)
  ctx.save()
  ctx.strokeStyle = `rgba(138,188,255,${0.26 + ring * 0.08})`
  ctx.lineWidth = 1.25
  ctx.beginPath()
  ctx.ellipse(atomCx, atomCy, rx, ry, 0, 0, Math.PI * 2)
  ctx.stroke()
  ctx.restore()
}

const electronAngles = [0.1, 1.65, 3.35, 5.15]
electronAngles.forEach((angle, idx) => {
  const rx = rxBase * (1.1 + idx * 0.52)
  const ry = ryBase * (1.1 + idx * 0.50)
  const ex = atomCx + Math.cos(angle + idx * 0.15) * rx
  const ey = atomCy + Math.sin(angle + idx * 0.15) * ry
  ctx.save()
  ctx.fillStyle = '#9fe6ff'
  ctx.shadowBlur = 10
  ctx.shadowColor = 'rgba(143,230,255,0.52)'
  ctx.beginPath()
  ctx.arc(ex, ey, 5.2, 0, Math.PI * 2)
  ctx.fill()
  ctx.restore()
})

const t = (Math.sin(time * 0.0022) + 1) * 0.5
const startRx = rxBase * (1.1 + 2 * 0.52)
const startRy = ryBase * (1.1 + 2 * 0.50)
const endRx = rxBase * (1.1 + 1 * 0.52)
const endRy = ryBase * (1.1 + 1 * 0.50)
const angle = -0.3
const movingX = atomCx + Math.cos(angle) * (startRx * (1 - t) + endRx * t)
const movingY = atomCy + Math.sin(angle) * (startRy * (1 - t) + endRy * t)
ctx.save()
ctx.strokeStyle = 'rgba(255,224,142,0.35)'
ctx.lineWidth = 1.6
ctx.beginPath()
ctx.moveTo(atomCx + Math.cos(angle) * startRx, atomCy + Math.sin(angle) * startRy)
ctx.lineTo(atomCx + Math.cos(angle) * endRx, atomCy + Math.sin(angle) * endRy)
ctx.stroke()
const moveGlow = ctx.createRadialGradient(movingX, movingY, 0, movingX, movingY, 26)
moveGlow.addColorStop(0, 'rgba(255,236,180,0.95)')
moveGlow.addColorStop(0.45, 'rgba(255,199,118,0.52)')
moveGlow.addColorStop(1, 'rgba(255,199,118,0)')
ctx.fillStyle = moveGlow
ctx.beginPath()
ctx.arc(movingX, movingY, 26, 0, Math.PI * 2)
ctx.fill()
ctx.fillStyle = '#fff6df'
ctx.beginPath()
ctx.arc(movingX, movingY, 5.6, 0, Math.PI * 2)
ctx.fill()
ctx.restore()

const nucleusGlow = ctx.createRadialGradient(atomCx, atomCy, 0, atomCx, atomCy, 24)
nucleusGlow.addColorStop(0, 'rgba(158,241,141,0.95)')
nucleusGlow.addColorStop(1, 'rgba(158,241,141,0)')
