function drawOrbitPlane(radius, extent, mode = 'xz', color = 'rgba(178,190,210,.72)'){
ctx.beginPath()
for(let i = 0; i <= 180; i += 1){
const t = Math.PI * 2 * i / 180
let x = 0, y = 0, z = 0
if(mode === 'xz'){
x = radius * Math.cos(t)
y = 0.18 * Math.sin(2 * t)
z = radius * Math.sin(t) * 0.72
}else if(mode === 'xy'){
x = radius * Math.cos(t)
y = radius * Math.sin(t) * 0.82
z = 0.35 * Math.sin(2 * t)
}else if(mode === 'yz'){
x = 0.32 * Math.sin(2 * t)
y = radius * Math.cos(t) * 0.82
z = radius * Math.sin(t)
}
const p = projectPoint(x,y,z,extent)
if(i === 0) ctx.moveTo(p.x,p.y)
else ctx.lineTo(p.x,p.y)
}
ctx.strokeStyle = color
ctx.lineWidth = 1.25
ctx.stroke()
}

function drawOrbitElectron(radius, speed, phase, extent, mode = 'xz', color = '#ff5d5d'){
const t = performance.now() * 0.001 * speed + phase
let x = 0, y = 0, z = 0
if(mode === 'xz'){
x = radius * Math.cos(t)
y = 0.18 * Math.sin(2 * t)
z = radius * Math.sin(t) * 0.72
}else if(mode === 'xy'){
x = radius * Math.cos(t)
y = radius * Math.sin(t) * 0.82
z = 0.35 * Math.sin(2 * t)
}else if(mode === 'yz'){
x = 0.32 * Math.sin(2 * t)
y = radius * Math.cos(t) * 0.82
z = radius * Math.sin(t)
}
const p = projectPoint(x,y,z,extent)
ctx.fillStyle = color
ctx.beginPath()
ctx.arc(p.x,p.y,Math.max(2.8,p.size * .072),0,Math.PI * 2)
ctx.fill()
ctx.fillStyle = 'rgba(255,255,255,.35)'
ctx.beginPath()
ctx.arc(p.x,p.y,Math.max(0.7,p.size * .026),0,Math.PI * 2)
ctx.fill()
}

function drawCrookesTube(extent, time){
const w = 5.8, h = 1.45, d = 1.45
const verts = [
[-w,-h,-d], [w,-h,-d], [w,h,-d], [-w,h,-d],
[-w,-h,d], [w,-h,d], [w,h,d], [-w,h,d]
]
const edges = [[0,1],[1,2],[2,3],[3,0],[4,5],[5,6],[6,7],[7,4],[0,4],[1,5],[2,6],[3,7]]
const phase = (time * 0.00034) % 1
const negativeSegment = phase < 0.5
const segmentT = negativeSegment ? phase / 0.5 : (phase - 0.5) / 0.5
const approach = Math.sin(segmentT * Math.PI)
const smooth = approach * approach * (3 - 2 * approach)
const positiveNear = !negativeSegment
const magnetX = 6.25 - smooth * 2.7
const magnetY = 2.68 - smooth * 0.68
const beamDeflect = (positiveNear ? 1 : -1) * smooth * 1.05
ctx.strokeStyle = 'rgba(156,214,255,.34)'
ctx.lineWidth = 1.2
edges.forEach(([a,b]) => {
const pa = projectPoint(...verts[a], extent)
const pb = projectPoint(...verts[b], extent)
ctx.beginPath()
ctx.moveTo(pa.x, pa.y)
ctx.lineTo(pb.x, pb.y)
ctx.stroke()
})
const cath = projectPoint(-5.1,0,0,extent)
const an = projectPoint(3.85,0,0,extent)
const beamStart = {x:cath.x + 12, y:cath.y}
const beamEnd = {x:an.x - 16, y:an.y + beamDeflect * 26}
const beamC1 = {x:cath.x + 84, y:cath.y + beamDeflect * 6}
const beamC2 = {x:an.x - 92, y:an.y + beamDeflect * 22}
const beamGlow = 0.72 + 0.28 * smooth
ctx.save()
ctx.globalCompositeOperation = 'screen'
ctx.shadowBlur = 28
ctx.shadowColor = 'rgba(110,255,210,.55)'
ctx.strokeStyle = `rgba(96,255,206,${0.05 + 0.03 * beamGlow})`
ctx.lineWidth = 24
ctx.beginPath()
ctx.moveTo(beamStart.x, beamStart.y)
ctx.bezierCurveTo(beamC1.x, beamC1.y, beamC2.x, beamC2.y, beamEnd.x, beamEnd.y)
ctx.stroke()
ctx.shadowBlur = 18
ctx.shadowColor = 'rgba(168,255,228,.72)'
ctx.strokeStyle = `rgba(144,255,220,${0.14 + 0.08 * beamGlow})`
ctx.lineWidth = 14
ctx.beginPath()
ctx.moveTo(beamStart.x, beamStart.y)
ctx.bezierCurveTo(beamC1.x, beamC1.y, beamC2.x, beamC2.y, beamEnd.x, beamEnd.y)
ctx.stroke()
ctx.shadowBlur = 10
ctx.shadowColor = 'rgba(232,255,248,.92)'
ctx.strokeStyle = `rgba(242,255,250,${0.42 + 0.12 * beamGlow})`
ctx.lineWidth = 5.2
ctx.beginPath()
ctx.moveTo(beamStart.x, beamStart.y)
ctx.bezierCurveTo(beamC1.x, beamC1.y, beamC2.x, beamC2.y, beamEnd.x, beamEnd.y)
ctx.stroke()
ctx.shadowBlur = 0
const tubeGlow = ctx.createRadialGradient(beamEnd.x, beamEnd.y, 3, beamEnd.x, beamEnd.y, 30)
tubeGlow.addColorStop(0, 'rgba(238,255,246,.96)')
tubeGlow.addColorStop(0.2, 'rgba(170,255,223,.62)')
tubeGlow.addColorStop(0.55, 'rgba(92,255,193,.18)')
tubeGlow.addColorStop(1, 'rgba(92,255,193,0)')
ctx.fillStyle = tubeGlow
ctx.beginPath()
ctx.arc(beamEnd.x, beamEnd.y, 30, 0, Math.PI * 2)
ctx.fill()
const cathGlow = ctx.createRadialGradient(beamStart.x, beamStart.y, 2, beamStart.x, beamStart.y, 18)
cathGlow.addColorStop(0, 'rgba(255,255,255,.9)')
cathGlow.addColorStop(0.45, 'rgba(166,255,224,.42)')
cathGlow.addColorStop(1, 'rgba(166,255,224,0)')
ctx.fillStyle = cathGlow
ctx.beginPath()
ctx.arc(beamStart.x, beamStart.y, 18, 0, Math.PI * 2)
ctx.fill()
for(let i = 0; i < 7; i += 1){
const t = ((time * 0.00055) + i / 7) % 1
const u = 1 - t
const x = u*u*u*beamStart.x + 3*u*u*t*beamC1.x + 3*u*t*t*beamC2.x + t*t*t*beamEnd.x
const y = u*u*u*beamStart.y + 3*u*u*t*beamC1.y + 3*u*t*t*beamC2.y + t*t*t*beamEnd.y
const r = 4.8 - t * 2.3
ctx.fillStyle = `rgba(235,255,247,${0.28 + 0.4 * (1 - t)})`
ctx.beginPath()
ctx.arc(x, y, r, 0, Math.PI * 2)
ctx.fill()
}
ctx.restore()
ctx.fillStyle = '#ff5555'
ctx.beginPath(); ctx.arc(cath.x,cath.y,13,0,Math.PI*2); ctx.fill()
ctx.fillStyle = '#8fb9ff'
ctx.beginPath(); ctx.arc(an.x,an.y,12,0,Math.PI*2); ctx.fill()
ctx.fillStyle = '#ffffff'
ctx.font = '700 16px Inter, system-ui, sans-serif'
ctx.textAlign = 'center'
ctx.textBaseline = 'middle'
ctx.fillText('−', cath.x, cath.y + .5)
ctx.fillText('+', an.x, an.y + .5)
const arrowStart = projectPoint(-4.35, -1.85, 0, extent)
const arrowEnd = projectPoint(2.85, -1.85, 0, extent)
ctx.strokeStyle = 'rgba(230,242,255,.9)'
ctx.lineWidth = 2.4
ctx.beginPath()
ctx.moveTo(arrowStart.x, arrowStart.y)
ctx.lineTo(arrowEnd.x, arrowEnd.y)
ctx.stroke()
ctx.beginPath()
ctx.moveTo(arrowEnd.x, arrowEnd.y)
ctx.lineTo(arrowEnd.x - 9, arrowEnd.y - 5)
ctx.lineTo(arrowEnd.x - 9, arrowEnd.y + 5)
ctx.closePath()
ctx.fillStyle = 'rgba(230,242,255,.9)'
ctx.fill()
ctx.font = '700 12px Inter, system-ui, sans-serif'
ctx.fillStyle = 'rgba(232,242,255,.96)'
ctx.fillText('feixe: − → +', (arrowStart.x + arrowEnd.x) * 0.5, arrowEnd.y - 10)
const bodyLeft = projectPoint(magnetX - 0.9, magnetY - 0.55, 0, extent)
const bodyRight = projectPoint(magnetX + 0.9, magnetY + 0.55, 0, extent)
const nearColor = positiveNear ? '#ff5757' : '#6fb2ff'
const farColor = positiveNear ? '#6fb2ff' : '#ff5757'
const splitP = projectPoint(magnetX, magnetY, 0, extent)
ctx.save()
ctx.fillStyle = nearColor
ctx.fillRect(bodyLeft.x, bodyLeft.y, splitP.x - bodyLeft.x, bodyRight.y - bodyLeft.y)
ctx.fillStyle = farColor
ctx.fillRect(splitP.x, bodyLeft.y, bodyRight.x - splitP.x, bodyRight.y - bodyLeft.y)
ctx.strokeStyle = 'rgba(235,244,255,.85)'
ctx.lineWidth = 1.8
ctx.strokeRect(bodyLeft.x, bodyLeft.y, bodyRight.x - bodyLeft.x, bodyRight.y - bodyLeft.y)
ctx.fillStyle = '#ffffff'
ctx.font = '900 18px Inter, system-ui, sans-serif'
ctx.textAlign = 'center'
ctx.textBaseline = 'middle'
ctx.fillText(positiveNear ? '−' : '+', (bodyLeft.x + splitP.x) * 0.5, (bodyLeft.y + bodyRight.y) * 0.5)
ctx.fillText(positiveNear ? '+' : '−', (splitP.x + bodyRight.x) * 0.5, (bodyLeft.y + bodyRight.y) * 0.5)
ctx.restore()
const nearLabel = projectPoint(magnetX - 0.05, magnetY + 1.0, 0, extent)
ctx.font = '700 12px Inter, system-ui, sans-serif'
ctx.textAlign = 'center'
ctx.fillStyle = positiveNear ? 'rgba(255,165,165,.96)' : 'rgba(166,210,255,.96)'
ctx.fillText(positiveNear ? 'negativo repele' : 'positivo atrai', nearLabel.x, nearLabel.y)
const farLabel = projectPoint(magnetX - 0.05, magnetY + 1.45, 0, extent)
ctx.fillStyle = 'rgba(228,238,255,.9)'
ctx.fillText(positiveNear ? 'polo − chegando perto' : 'polo + chegando perto', farLabel.x, farLabel.y)
}

function drawMillikan(extent, time){
const plateHalfW = 2.9
const plateDepth = 1.65
const topY = 2.0
const bottomY = -2.0
const topPlate = [
projectPoint(-plateHalfW, topY, -plateDepth, extent),
projectPoint(plateHalfW, topY, -plateDepth, extent),
projectPoint(plateHalfW, topY, plateDepth, extent),
projectPoint(-plateHalfW, topY, plateDepth, extent)
]
const bottomPlate = [
projectPoint(-plateHalfW, bottomY, -plateDepth, extent),
projectPoint(plateHalfW, bottomY, -plateDepth, extent),
projectPoint(plateHalfW, bottomY, plateDepth, extent),
projectPoint(-plateHalfW, bottomY, plateDepth, extent)
]
;[[topPlate,'rgba(195,207,232,.22)','rgba(214,226,255,.72)'],[bottomPlate,'rgba(195,207,232,.18)','rgba(214,226,255,.68)']].forEach(([plate,fill,stroke]) => {
ctx.fillStyle = fill
ctx.strokeStyle = stroke
ctx.lineWidth = 1.5
ctx.beginPath()
ctx.moveTo(plate[0].x, plate[0].y)
for(let i = 1; i < plate.length; i += 1) ctx.lineTo(plate[i].x, plate[i].y)
ctx.closePath()
ctx.fill()
ctx.stroke()
})
for(let x = -2.0; x <= 2.0; x += 1.0){
for(let z = -1.1; z <= 1.1; z += 1.1){
drawFieldArrow3D(x, topY - 0.18, bottomY + 0.28, z, extent)
}
}
const nozzleA = projectPoint(-5.1,3.6,0,extent)
const nozzleB = projectPoint(-3.2,2.35,0,extent)
ctx.strokeStyle = 'rgba(149,255,218,.45)'
ctx.lineWidth = 4
ctx.beginPath()
ctx.moveTo(nozzleA.x,nozzleA.y)
ctx.lineTo(nozzleB.x,nozzleB.y)
ctx.stroke()
for(let i = 0; i < 22; i += 1){
const t = (time * 0.00030 + i / 22) % 1
const x = -3.1 + 4.9 * t
const y = 1.6 - 2.7 * t + 0.25 * Math.sin(time * 0.002 + i)
const z = -0.95 + (i % 5) * 0.46
const p = projectPoint(x, y, z, extent)
const radius = 1.5 + (i % 3) * 0.7
ctx.fillStyle = 'rgba(230,240,255,.72)'
ctx.beginPath()
ctx.arc(p.x, p.y, radius, 0, Math.PI * 2)
ctx.fill()
}
const hoverY = 0.18 + 0.12 * Math.sin(time * 0.0018)
const mainDrop = projectPoint(0.35, hoverY, 0.15, extent)
const halo = ctx.createRadialGradient(mainDrop.x, mainDrop.y, 2, mainDrop.x, mainDrop.y, 22)
halo.addColorStop(0, 'rgba(255,246,196,.62)')
halo.addColorStop(1, 'rgba(255,246,196,0)')
ctx.fillStyle = halo
ctx.beginPath()
ctx.arc(mainDrop.x, mainDrop.y, 22, 0, Math.PI * 2)
ctx.fill()
ctx.fillStyle = 'rgba(255,230,136,.96)'
ctx.beginPath()
ctx.arc(mainDrop.x, mainDrop.y, 5.3, 0, Math.PI * 2)
ctx.fill()
ctx.fillStyle = 'rgba(255,255,255,.92)'
ctx.beginPath()
ctx.arc(mainDrop.x - 1.4, mainDrop.y - 1.6, 1.4, 0, Math.PI * 2)
ctx.fill()
const qx = mainDrop.x + 18
const qy = mainDrop.y - 18
ctx.strokeStyle = 'rgba(255,210,122,.85)'
ctx.lineWidth = 1.6
ctx.beginPath()
ctx.moveTo(mainDrop.x + 6, mainDrop.y - 6)
ctx.lineTo(qx - 7, qy + 7)
ctx.stroke()
ctx.fillStyle = 'rgba(255,210,122,.96)'
ctx.beginPath()
ctx.arc(qx, qy, 9, 0, Math.PI * 2)
ctx.fill()
ctx.fillStyle = '#172235'
ctx.font = 'bold 12px Inter, system-ui, sans-serif'
ctx.fillText('q', qx - 3.5, qy + 4)
}

function drawGoldFoilExperiment(extent, time){
const foil = [projectPoint(0,-2.2,-1.5,extent), projectPoint(0,2.2,-1.5,extent), projectPoint(0,2.2,1.5,extent), projectPoint(0,-2.2,1.5,extent)]
ctx.fillStyle = 'rgba(255,214,92,.20)'
ctx.strokeStyle = 'rgba(255,214,92,.72)'
ctx.lineWidth = 1.5
ctx.beginPath()
ctx.moveTo(foil[0].x,foil[0].y)
for(let i = 1; i < foil.length; i += 1) ctx.lineTo(foil[i].x,foil[i].y)
ctx.closePath()
ctx.fill()
ctx.stroke()

const source = projectPoint(-6.3,0,0,extent)
ctx.fillStyle = '#8f59ff'
ctx.beginPath()
ctx.arc(source.x,source.y,10,0,Math.PI*2)
ctx.fill()

const particles = 4
for(let i = 0; i < particles; i += 1){
const cycle = ((time * 0.00022) + i / particles) % 1
const laneY = (i - (particles - 1) * 0.5) * 0.56
const laneZ = (i % 2 === 0 ? -1 : 1) * 0.32
let x = -5.7 + cycle * 10.8
let y = laneY
let z = laneZ
const isBounceParticle = i === 0 || i === particles - 1

if(isBounceParticle){
const hitStart = 0.43
const hitPeak = 0.57
if(cycle < hitStart){
x = -5.7 + (cycle / hitStart) * 4.7
}else if(cycle < hitPeak){
const t = (cycle - hitStart) / (hitPeak - hitStart)
x = -0.55 + t * 0.55
y = laneY + (i === 0 ? 1 : -1) * 1.02 * t
z = laneZ + (i === 0 ? 1 : -1) * 0.38 * t
}else{
const t = (cycle - hitPeak) / (1 - hitPeak)
x = -0.08 - t * 3.5
y = laneY + (i === 0 ? 1 : -1) * (1.02 - 0.18 * t)
z = laneZ + (i === 0 ? 1 : -1) * (0.38 - 0.08 * t)
}
}else if(i % 4 === 0){
if(x > -0.45 && x < 0.65){
const k = (x + 0.45) / 1.10
y += Math.sin(k * Math.PI) * 0.42 * (i % 8 === 0 ? 1 : -1)
z += Math.sin(k * Math.PI) * 0.20 * (i % 3 === 0 ? 1 : -1)
}
}else{
if(x > -0.2 && x < 0.35){
const k = 0.35 - Math.abs(x - 0.075)
y += (i % 2 === 0 ? 1 : -1) * k * 0.10
z += (i % 3 === 0 ? 1 : -1) * k * 0.07
}
}

const p = projectPoint(x,y,z,extent)
ctx.fillStyle = 'rgba(255,72,72,.96)'
ctx.beginPath()
ctx.arc(p.x,p.y,Math.max(2,p.size * 0.014),0,Math.PI*2)
ctx.fill()

if(showTrailsControl.checked){
const trailStart = isBounceParticle ? projectPoint(x + 0.26, y, z, extent) : projectPoint(x - 0.34, y, z, extent)
ctx.strokeStyle = isBounceParticle ? 'rgba(255,108,108,.24)' : 'rgba(255,108,108,.16)'
ctx.lineWidth = 1
ctx.beginPath()
ctx.moveTo(trailStart.x, trailStart.y)
ctx.lineTo(p.x, p.y)
ctx.stroke()
}
}

const nucleus = projectPoint(0,0,0,extent)
ctx.fillStyle = '#7df5a2'
ctx.beginPath()
ctx.arc(nucleus.x,nucleus.y,6,0,Math.PI*2)
ctx.fill()
}

