function drawRutherfordModel(extent){
const nucleus = projectPoint(0,0,0,extent)
const positions = [
  {x:2.65,y:0.22,z:0.18},
  {x:-2.18,y:1.16,z:-0.24},
  {x:-1.58,y:-1.62,z:0.28}
]
positions.forEach((item, index) => {
  const p = projectPoint(item.x, item.y, item.z, extent)
  const halo = ctx.createRadialGradient(p.x,p.y,0,p.x,p.y,18)
  halo.addColorStop(0,'rgba(255,176,176,.44)')
  halo.addColorStop(1,'rgba(255,93,93,0)')
  ctx.fillStyle = halo
  ctx.beginPath(); ctx.arc(p.x,p.y,18,0,Math.PI*2); ctx.fill()
  ctx.fillStyle = index === 1 ? '#ff7474' : '#ff5d5d'
  ctx.beginPath(); ctx.arc(p.x,p.y,Math.max(4.5, p.size * 0.082),0,Math.PI*2); ctx.fill()
})
ctx.strokeStyle = 'rgba(255,214,134,.24)'
ctx.lineWidth = 1.1
for(let i = 0; i < 3; i += 1){
  ctx.beginPath()
  ctx.arc(nucleus.x, nucleus.y, 14 + i * 9, 0, Math.PI * 2)
  ctx.stroke()
}
drawNucleus(10, extent, '#9ef18d')
}

function drawBohrModel(extent){
const viewWidth = canvas.width / devicePixelRatio
const viewHeight = canvas.height / devicePixelRatio
const center = {x:viewWidth * 0.5, y:viewHeight * 0.5}
const scale = sceneOrthoScale(extent)
const radii = [2.05, 3.0, 3.95]
ctx.save()
ctx.strokeStyle = 'rgba(146,190,255,.34)'
ctx.lineWidth = 1.5
radii.forEach((radius) => {
  const pr = radius * scale
  ctx.beginPath()
  ctx.arc(center.x, center.y, pr, 0, Math.PI * 2)
  ctx.stroke()
})
const t = performance.now() * 0.001
const phases = [0.5, 1.8, 3.2]
const speeds = [0.8, 1.1, 0.7]
radii.forEach((radius, index) => {
  const pr = radius * scale
  const ang = t * speeds[index] + phases[index]
  const ex = center.x + Math.cos(ang) * pr
  const ey = center.y + Math.sin(ang) * pr
  const halo = ctx.createRadialGradient(ex,ey,0,ex,ey,15)
  halo.addColorStop(0,'rgba(255,188,188,.42)')
  halo.addColorStop(1,'rgba(255,93,93,0)')
  ctx.fillStyle = halo
  ctx.beginPath(); ctx.arc(ex,ey,15,0,Math.PI*2); ctx.fill()
  ctx.fillStyle = '#ff5d5d'
  ctx.beginPath(); ctx.arc(ex,ey,5.2,0,Math.PI*2); ctx.fill()
})
ctx.restore()
drawNucleus(10, extent, '#9ef18d')
}

