function drawSommerfeldModel(extent){
const viewWidth = canvas.width / devicePixelRatio
const viewHeight = canvas.height / devicePixelRatio
const center = {x:viewWidth * 0.5, y:viewHeight * 0.5}
const scale = sceneOrthoScale(extent)
const radii = [2.2, 3.35]
const minor = [0.62, 0.72]
const rotations = [0.48, -0.32]
ctx.save()
ctx.strokeStyle = 'rgba(146,190,255,.34)'
ctx.lineWidth = 1.4
radii.forEach((radius, index) => {
  const rx = radius * scale
  const ry = rx * minor[index]
  ctx.beginPath()
  ctx.ellipse(center.x, center.y, rx, ry, rotations[index], 0, Math.PI * 2)
  ctx.stroke()
})
const t = performance.now() * 0.001
radii.forEach((radius, index) => {
  const rx = radius * scale
  const ry = rx * minor[index]
  const ang = t * (index === 0 ? 1.2 : 0.8) + (index === 0 ? 0.2 : 1.2)
  const rot = rotations[index]
  const ex = center.x + Math.cos(ang) * rx * Math.cos(rot) - Math.sin(ang) * ry * Math.sin(rot)
  const ey = center.y + Math.cos(ang) * rx * Math.sin(rot) + Math.sin(ang) * ry * Math.cos(rot)
  const halo = ctx.createRadialGradient(ex,ey,0,ex,ey,15)
  halo.addColorStop(0,'rgba(255,188,188,.42)')
  halo.addColorStop(1,'rgba(255,93,93,0)')
  ctx.fillStyle = halo
  ctx.beginPath(); ctx.arc(ex,ey,15,0,Math.PI*2); ctx.fill()
  ctx.fillStyle = '#ff5d5d'
  ctx.beginPath(); ctx.arc(ex,ey,5.0,0,Math.PI*2); ctx.fill()
})
ctx.restore()
drawNucleus(10, extent, '#9ef18d')
}

