function drawProbabilisticOrbitalCloud(points, extent, palette = null){
const projected = []
for(let i = 0; i < points.length; i += 1){
const point = points[i]
const proj = projectPoint(point.x, point.y, point.z, extent)
projected.push({point, proj})
}
projected.sort((a,b) => a.proj.z - b.proj.z)
const activePalette = palette || {base:[255,170,86], halo:[255,121,34], spark:[255,255,255], accent:[255,210,140]}
const dotSprite = getPointSprite(activePalette.base, 'dot')
const softSprite = getPointSprite(activePalette.halo, 'soft')
ctx.save()
ctx.globalCompositeOperation = 'screen'
const stride = projected.length > 6400 ? 2 : 1
for(let i = 0; i < projected.length; i += stride){
const item = projected[i]
const point = item.point
const proj = item.proj
const depth = Math.max(0, Math.min(1, (proj.z + extent) / (extent * 2)))
const alpha = Math.max(0.025, Math.min(0.22, (point.alpha ?? 0.1) * (0.78 + depth * 0.72)))
const dotRadius = Math.max(0.48, proj.size * 0.15 * (point.renderScale ?? 1))
if(i % 12 === 0){
const softRadius = Math.max(1.0, dotRadius * (1.7 + (point.glow ?? 0.4) * 0.6))
ctx.globalAlpha = alpha * 0.18
ctx.drawImage(softSprite, proj.x - softRadius, proj.y - softRadius, softRadius * 2, softRadius * 2)
}
ctx.globalAlpha = alpha
ctx.drawImage(dotSprite, proj.x - dotRadius, proj.y - dotRadius, dotRadius * 2, dotRadius * 2)
}
ctx.restore()
}

function drawOrbitalCloud3D(points, extent, colorA = [255,255,255], colorB = [216,228,255], pointSize = 1){
drawProbabilisticOrbitalCloud(points, extent, orbitalDisplayPalette(state.orbital.n, state.orbital.l))
}

