function drawScaleChargeScene(time){
const w = canvas.width / devicePixelRatio
const h = canvas.height / devicePixelRatio
const boardW = Math.min(w - 56, 980)
const boardH = Math.min(h - 64, 620)
const bx = (w - boardW) * 0.5
const by = (h - boardH) * 0.5
drawBoardFrame(bx, by, boardW, boardH)
drawBoardLabel('escala do átomo', bx + 34, by + 46, 24, 'left', 'rgba(255,255,255,0.96)', 700)
drawBoardLabel('núcleo positivo minúsculo • elétrons negativos na região externa', bx + 34, by + 74, 13, 'left', 'rgba(200,214,238,0.84)', 600)

const atomCx = bx + boardW * 0.37
const atomCy = by + boardH * 0.56
const atomR = Math.min(boardH * 0.36, boardW * 0.24)
const pulse = 0.5 + 0.5 * Math.sin(time * 0.0022)
const nucleusR = 8
const nucleusGlowR = 42

ctx.save()
ctx.globalCompositeOperation = 'screen'
for(let i = 0; i < 3; i += 1){
ctx.strokeStyle = `rgba(120,210,255,${0.12 - i * 0.025})`
ctx.lineWidth = 18 - i * 5
ctx.beginPath()
ctx.arc(atomCx, atomCy, atomR + i * 7 + pulse * 4, 0, Math.PI * 2)
ctx.stroke()
}
ctx.restore()

ctx.strokeStyle = 'rgba(148,214,255,0.90)'
ctx.lineWidth = 2
ctx.beginPath()
ctx.arc(atomCx, atomCy, atomR, 0, Math.PI * 2)
ctx.stroke()

const orbitRs = [atomR * 0.56, atomR * 0.76, atomR * 0.94]
const orbitShapes = [
{e:0.28, rot:0.35},
{e:0.48, rot:1.12},
{e:0.64, rot:2.16}
]
orbitRs.forEach((r, idx) => {
const shape = orbitShapes[idx]
ctx.strokeStyle = `rgba(255,255,255,${0.11 + idx * 0.04})`
ctx.lineWidth = 1.1
ctx.beginPath()
ctx.ellipse(atomCx, atomCy, r, r * (1 - shape.e), shape.rot, 0, Math.PI * 2)
ctx.stroke()
})

const ellipsePoint = (cx, cy, a, b, rot, theta) => {
const ct = Math.cos(theta)
const st = Math.sin(theta)
const cr = Math.cos(rot)
const sr = Math.sin(rot)
return {
x: cx + a * ct * cr - b * st * sr,
y: cy + a * ct * sr + b * st * cr
}
}

const electrons = [
{a: time * 0.0018 + 0.30, r: orbitRs[0], b: orbitRs[0] * (1 - orbitShapes[0].e), rot: orbitShapes[0].rot},
{a: time * 0.0018 + 3.44, r: orbitRs[0], b: orbitRs[0] * (1 - orbitShapes[0].e), rot: orbitShapes[0].rot},
{a: -time * 0.00135 + 1.10, r: orbitRs[1], b: orbitRs[1] * (1 - orbitShapes[1].e), rot: orbitShapes[1].rot},
{a: -time * 0.00135 + 4.26, r: orbitRs[1], b: orbitRs[1] * (1 - orbitShapes[1].e), rot: orbitShapes[1].rot},
{a: time * 0.0011 + 0.70, r: orbitRs[2], b: orbitRs[2] * (1 - orbitShapes[2].e), rot: orbitShapes[2].rot},
{a: time * 0.0011 + 3.84, r: orbitRs[2], b: orbitRs[2] * (1 - orbitShapes[2].e), rot: orbitShapes[2].rot}
]
electrons.forEach((el) => {
const p = ellipsePoint(atomCx, atomCy, el.r, el.b, el.rot, el.a)
ctx.fillStyle = '#58b8ff'
ctx.beginPath()
ctx.arc(p.x, p.y, 10.5, 0, Math.PI * 2)
ctx.fill()
ctx.fillStyle = '#ffffff'
ctx.font = '900 14px Inter, system-ui, sans-serif'
ctx.textAlign = 'center'
ctx.textBaseline = 'middle'
ctx.fillText('−', p.x, p.y + 0.5)
})


ctx.save()
ctx.globalCompositeOperation = 'screen'
const nucleusGlow = ctx.createRadialGradient(atomCx, atomCy, 0, atomCx, atomCy, nucleusGlowR)
nucleusGlow.addColorStop(0, 'rgba(255,204,118,0.95)')
nucleusGlow.addColorStop(0.22, 'rgba(255,168,66,0.74)')
nucleusGlow.addColorStop(0.64, 'rgba(255,120,34,0.14)')
nucleusGlow.addColorStop(1, 'rgba(255,120,34,0)')
ctx.fillStyle = nucleusGlow
ctx.beginPath()
ctx.arc(atomCx, atomCy, nucleusGlowR, 0, Math.PI * 2)
ctx.fill()
ctx.restore()

ctx.fillStyle = '#ff9a3c'
ctx.beginPath()
ctx.arc(atomCx, atomCy, nucleusR, 0, Math.PI * 2)
ctx.fill()
ctx.fillStyle = '#ffffff'
ctx.font = '900 14px Inter, system-ui, sans-serif'
ctx.textAlign = 'center'
ctx.textBaseline = 'middle'
ctx.fillText('+', atomCx, atomCy + 0.5)

ctx.strokeStyle = 'rgba(255,255,255,0.18)'
ctx.lineWidth = 2
ctx.beginPath()
ctx.moveTo(atomCx + atomR + 24, atomCy - atomR * 0.36)
ctx.lineTo(bx + boardW * 0.72, by + boardH * 0.36)
ctx.stroke()

const zoomCx = bx + boardW * 0.78
const zoomCy = by + boardH * 0.34
const zoomR = 78
ctx.save()
ctx.globalCompositeOperation = 'screen'
const zoomGlow = ctx.createRadialGradient(zoomCx, zoomCy, 0, zoomCx, zoomCy, zoomR)
zoomGlow.addColorStop(0, 'rgba(255,180,90,0.30)')
zoomGlow.addColorStop(1, 'rgba(255,180,90,0)')
ctx.fillStyle = zoomGlow
ctx.beginPath()
ctx.arc(zoomCx, zoomCy, zoomR, 0, Math.PI * 2)
ctx.fill()
ctx.restore()
ctx.strokeStyle = 'rgba(255,208,140,0.92)'
ctx.lineWidth = 2
ctx.beginPath()
ctx.arc(zoomCx, zoomCy, zoomR, 0, Math.PI * 2)
ctx.stroke()
const zoomCycle = (time * 0.00062) % 1
const zoomApproachEnd = 0.36
const zoomAlphaStartX = zoomCx - zoomR - 64
const zoomAlphaStartY = zoomCy + 4
let zoomAlphaX = zoomAlphaStartX
let zoomAlphaY = zoomAlphaStartY
let zoomHitStrength = 0
if(zoomCycle <= zoomApproachEnd){
const t = zoomCycle / zoomApproachEnd
const eased = t * t * (3 - 2 * t)
zoomAlphaX = zoomAlphaStartX + (zoomCx - zoomAlphaStartX) * eased
zoomAlphaY = zoomAlphaStartY + (zoomCy - zoomAlphaStartY) * eased
zoomHitStrength = Math.max(0, (eased - 0.86) / 0.14)
}else{
const t = (zoomCycle - zoomApproachEnd) / (1 - zoomApproachEnd)
const eased = t * t * (3 - 2 * t)
const reboundX = zoomCx - zoomR * 0.62 - 34
const reboundY = zoomCy - zoomR * 0.18
zoomAlphaX = zoomCx + (reboundX - zoomCx) * eased
zoomAlphaY = zoomCy + (reboundY - zoomCy) * eased
zoomHitStrength = Math.max(0, 1 - eased * 2.4)
}
ctx.save()
ctx.globalCompositeOperation = 'screen'
const zoomTrailStartX = zoomCycle <= zoomApproachEnd ? zoomAlphaStartX : zoomCx
const zoomTrailStartY = zoomCycle <= zoomApproachEnd ? zoomAlphaStartY : zoomCy
const zoomAlphaTrail = ctx.createLinearGradient(zoomTrailStartX, zoomTrailStartY, zoomAlphaX, zoomAlphaY)
zoomAlphaTrail.addColorStop(0, 'rgba(255,120,120,0)')
zoomAlphaTrail.addColorStop(1, 'rgba(255,120,120,0.48)')
ctx.strokeStyle = zoomAlphaTrail
ctx.lineWidth = 8
ctx.beginPath()
ctx.moveTo(zoomTrailStartX, zoomTrailStartY)
ctx.lineTo(zoomAlphaX, zoomAlphaY)
ctx.stroke()
if(zoomHitStrength > 0){
const zoomImpactGlow = ctx.createRadialGradient(zoomCx, zoomCy, 0, zoomCx, zoomCy, 30)
zoomImpactGlow.addColorStop(0, `rgba(255,210,140,${0.28 + zoomHitStrength * 0.46})`)
zoomImpactGlow.addColorStop(1, 'rgba(255,210,140,0)')
ctx.fillStyle = zoomImpactGlow
ctx.beginPath()
ctx.arc(zoomCx, zoomCy, 30, 0, Math.PI * 2)
ctx.fill()
}
ctx.restore()

ctx.fillStyle = '#ff9a3c'
ctx.beginPath()
ctx.arc(zoomCx, zoomCy, 15, 0, Math.PI * 2)
ctx.fill()
ctx.fillStyle = '#ffffff'
ctx.font = '900 17px Inter, system-ui, sans-serif'
ctx.textAlign = 'center'
ctx.textBaseline = 'middle'
ctx.fillText('+', zoomCx, zoomCy + 0.5)

ctx.fillStyle = '#ff6767'
ctx.beginPath()
ctx.arc(zoomAlphaX, zoomAlphaY, 10.5, 0, Math.PI * 2)
ctx.fill()
ctx.fillStyle = '#ffffff'
ctx.font = '900 13px Inter, system-ui, sans-serif'
ctx.fillText('+', zoomAlphaX, zoomAlphaY + 0.5)

ctx.save()
ctx.fillStyle = 'rgba(226,236,255,0.92)'
ctx.font = '700 16px Inter, system-ui, sans-serif'
ctx.textAlign = 'left'
ctx.fillText('raio atômico ~ 10⁻¹⁰ m', bx + 36, by + boardH - 122)
ctx.fillText('raio nuclear ~ 10⁻¹⁵ m', bx + 36, by + boardH - 92)
ctx.font = '700 18px Inter, system-ui, sans-serif'
ctx.fillStyle = 'rgba(255,229,172,0.96)'
ctx.fillText('o núcleo é cerca de 100.000 vezes menor no raio', bx + 36, by + boardH - 50)
ctx.restore()
}

function drawInterferenceScreen(x, y, h, mode = 'wave'){
ctx.save()
const screenGrad = ctx.createLinearGradient(x, y, x + 26, y)
screenGrad.addColorStop(0, 'rgba(236,243,255,0.12)')
screenGrad.addColorStop(1, 'rgba(236,243,255,0.30)')
ctx.fillStyle = screenGrad
ctx.fillRect(x, y, 26, h)
ctx.strokeStyle = 'rgba(236,243,255,0.70)'
ctx.lineWidth = 2
ctx.strokeRect(x, y, 26, h)
for(let i = 0; i < 54; i += 1){
const t = i / 53
const yy = y + t * h
const fringe = Math.pow(Math.cos((t - 0.5) * Math.PI * 9), 2)
const envelope = Math.exp(-Math.pow((t - 0.5) / 0.34, 2))
const intensity = Math.max(0.04, fringe * envelope)
ctx.fillStyle = mode === 'quantum' ? `rgba(122,219,255,${0.06 + intensity * 0.55})` : `rgba(122,219,255,${0.10 + intensity * 0.82})`
ctx.fillRect(x + 2, yy - 2.2, 22 * intensity, 4.4)
}
ctx.restore()
}


function drawDoubleSlitWaveScene(time){
const w = canvas.width / devicePixelRatio
const h = canvas.height / devicePixelRatio
const boardW = Math.min(w - 56, 980)
const boardH = Math.min(h - 64, 620)
const bx = (w - boardW) * 0.5
const by = (h - boardH) * 0.5
const pad = 28
const innerX = bx + pad
const innerY = by + pad
const innerW = boardW - pad * 2
const innerH = boardH - pad * 2
const left = innerX + 10
const top = innerY + 24
const bottom = innerY + innerH - 24
const sy = (top + bottom) * 0.5
const barrierX = innerX + innerW * 0.44
const slitGap = 102
const slitRadius = 8
const slit1y = sy - slitGap * 0.5
const slit2y = sy + slitGap * 0.5
const screenX = innerX + innerW * 0.72
const screenW = 130
const stripeSpacing = 21
const waveTravel = (time * 0.010) % stripeSpacing
const arcDrift = (time * 0.010) % 24

 drawBoardFrame(bx, by, boardW, boardH)

ctx.save()
const glass = ctx.createLinearGradient(innerX, innerY, innerX, innerY + innerH)
glass.addColorStop(0, 'rgba(255,255,255,0.015)')
glass.addColorStop(0.5, 'rgba(255,255,255,0.00)')
glass.addColorStop(1, 'rgba(255,255,255,0.025)')
ctx.fillStyle = glass
ctx.fillRect(innerX, innerY, innerW, innerH)
ctx.restore()


ctx.save()
ctx.lineWidth = 2.1
ctx.shadowBlur = 10
ctx.shadowColor = 'rgba(120,180,255,0.18)'
for(let x = left - stripeSpacing * 2 + waveTravel; x <= barrierX - 12; x += stripeSpacing){
ctx.strokeStyle = 'rgba(112,158,236,0.70)'
ctx.beginPath()
ctx.moveTo(x, top + 12)
ctx.lineTo(x, bottom - 12)
ctx.stroke()
}
ctx.restore()

ctx.save()
ctx.fillStyle = 'rgba(8,12,20,0.96)'
ctx.fillRect(barrierX - 8, top, 16, bottom - top)
ctx.fillStyle = 'rgba(240,245,255,0.96)'
ctx.beginPath()
ctx.arc(barrierX, slit1y, slitRadius, 0, Math.PI * 2)
ctx.fill()
ctx.beginPath()
ctx.arc(barrierX, slit2y, slitRadius, 0, Math.PI * 2)
ctx.fill()
ctx.restore()

ctx.save()
ctx.lineWidth = 2.4
ctx.shadowBlur = 8
ctx.shadowColor = 'rgba(116,170,255,0.12)'
for(let i = 0; i < 15; i += 1){
const r = 24 + i * 23 + arcDrift
const alpha = Math.max(0.14, 0.62 - i * 0.028)
ctx.strokeStyle = `rgba(128,168,224,${alpha})`
ctx.beginPath()
ctx.arc(barrierX, slit1y, r, -0.88, 0.88)
ctx.stroke()
ctx.beginPath()
ctx.arc(barrierX, slit2y, r, -0.88, 0.88)
ctx.stroke()
}
ctx.restore()

ctx.save()
const screenGrad = ctx.createLinearGradient(screenX, top + 12, screenX + screenW, top + 12)
screenGrad.addColorStop(0, 'rgba(2,5,16,0.62)')
screenGrad.addColorStop(1, 'rgba(2,5,16,0.86)')
ctx.fillStyle = screenGrad
ctx.fillRect(screenX, top + 12, screenW, bottom - top - 24)
const bandYs = []
for(let i = -3; i <= 3; i += 1){
bandYs.push(sy + i * 66)
}
for(let i = 0; i < bandYs.length; i += 1){
const y = bandYs[i]
const band = ctx.createLinearGradient(screenX, y - 22, screenX, y + 22)
band.addColorStop(0, 'rgba(0,0,0,0)')
band.addColorStop(0.18, 'rgba(25,60,255,0.08)')
band.addColorStop(0.50, 'rgba(40,95,255,0.84)')
band.addColorStop(0.82, 'rgba(25,60,255,0.08)')
band.addColorStop(1, 'rgba(0,0,0,0)')
ctx.fillStyle = band
ctx.fillRect(screenX, y - 22, screenW, 44)
}
ctx.restore()

ctx.save()
ctx.fillStyle = 'rgba(232,238,250,0.92)'
ctx.font = 'italic 700 22px Georgia, serif'
ctx.textAlign = 'left'
ctx.textBaseline = 'middle'
const labels = ['m = 3','m = 2','m = 1','m = 0','m = 1','m = 2','m = 3']
for(let i = 0; i < bandYs.length; i += 1){
ctx.fillText(labels[i], screenX + screenW + 28, bandYs[i])
}
ctx.restore()
}

function drawDoubleSlitQuantumScene(time){
const w = canvas.width / devicePixelRatio
const h = canvas.height / devicePixelRatio
const boardW = Math.min(w - 56, 980)
const boardH = Math.min(h - 64, 620)
const bx = (w - boardW) * 0.5
const by = (h - boardH) * 0.5
const pad = 28
const innerX = bx + pad
const innerY = by + pad
const innerW = boardW - pad * 2
const innerH = boardH - pad * 2
const left = innerX + 10
const top = innerY + 24
const bottom = innerY + innerH - 24
const sy = (top + bottom) * 0.5
const barrierX = innerX + innerW * 0.34
const slitGap = 124
const slitHeight = 42
const detectorX = innerX + innerW * 0.70
const detectorW = 136
const detectorTop = top + 8
const detectorBottom = bottom - 8
const slit1y = sy - slitGap * 0.5
const slit2y = sy + slitGap * 0.5
const clusters = [slit1y + 2, slit2y - 2]

 drawBoardFrame(bx, by, boardW, boardH)
ctx.save()
const wash = ctx.createLinearGradient(innerX, innerY, innerX, innerY + innerH)
wash.addColorStop(0, 'rgba(255,255,255,0.03)')
wash.addColorStop(1, 'rgba(255,255,255,0.01)')
ctx.fillStyle = wash
ctx.fillRect(innerX, innerY, innerW, innerH)
ctx.restore()


ctx.save()
ctx.fillStyle = 'rgba(214,218,224,0.96)'
ctx.strokeStyle = 'rgba(68,72,78,0.92)'
ctx.lineWidth = 1.6
for(let i = 0; i < 26; i += 1){
const col = i % 6
const row = Math.floor(i / 6)
const jitter = Math.sin(i * 12.989) * 0.5 + 0.5
const x = left + 18 + col * 20 + (row % 2) * 7 + (jitter - 0.5) * 10
const y = sy - 108 + row * 30 + Math.cos(i * 9.123) * 10
ctx.beginPath()
ctx.arc(x, y, 4.1, 0, Math.PI * 2)
ctx.fill()
ctx.stroke()
}
ctx.restore()

ctx.save()
ctx.fillStyle = 'rgba(176,176,176,0.96)'
ctx.strokeStyle = 'rgba(74,74,74,0.96)'
ctx.lineWidth = 1.4
const blockX = barrierX - 14
const blockW = 28
const topBlockY = top + 12
const topBlockH = slit1y - slitHeight * 0.5 - topBlockY
const midBlockY = slit1y + slitHeight * 0.5
const midBlockH = slit2y - slitHeight * 0.5 - midBlockY
const botBlockY = slit2y + slitHeight * 0.5
const botBlockH = bottom - 12 - botBlockY
ctx.fillRect(blockX, topBlockY, blockW, topBlockH)
ctx.strokeRect(blockX, topBlockY, blockW, topBlockH)
ctx.fillRect(blockX, midBlockY, blockW, midBlockH)
ctx.strokeRect(blockX, midBlockY, blockW, midBlockH)
ctx.fillRect(blockX, botBlockY, blockW, botBlockH)
ctx.strokeRect(blockX, botBlockY, blockW, botBlockH)
ctx.restore()

ctx.save()
ctx.strokeStyle = 'rgba(128,128,128,0.90)'
ctx.lineWidth = 1.5
ctx.beginPath()
ctx.moveTo(barrierX + 14, slit1y)
ctx.lineTo(detectorX, clusters[0])
ctx.moveTo(barrierX + 14, slit2y)
ctx.lineTo(detectorX, clusters[1])
ctx.stroke()
ctx.restore()

ctx.save()
ctx.fillStyle = 'rgba(226,226,226,0.14)'
ctx.strokeStyle = 'rgba(230,230,230,0.78)'
ctx.lineWidth = 1.4
ctx.fillRect(detectorX, detectorTop, detectorW, detectorBottom - detectorTop)
ctx.strokeRect(detectorX, detectorTop, detectorW, detectorBottom - detectorTop)
ctx.restore()

const totalDots = 34
const reveal = Math.floor((((time * 0.00010) % 1) * 0.88 + 0.12) * totalDots)
ctx.save()
ctx.fillStyle = 'rgba(214,218,224,0.96)'
ctx.strokeStyle = 'rgba(68,72,78,0.92)'
ctx.lineWidth = 1.5
for(let i = 0; i < reveal; i += 1){
const clusterIndex = i % 2
const localIndex = Math.floor(i / 2)
const x = detectorX + 12 + (localIndex % 8) * 16 + ((clusterIndex * 7 + localIndex) % 3) * 1.8
const y = clusters[clusterIndex] + ((localIndex * 17 + clusterIndex * 11) % 5 - 2) * 9 + ((localIndex % 2) ? 2 : -2)
ctx.beginPath()
ctx.arc(x, y, 4.2, 0, Math.PI * 2)
ctx.fill()
ctx.stroke()
}
ctx.restore()

const movingParticles = 8
const streamSpeed = time * 0.00011
ctx.save()
ctx.fillStyle = 'rgba(214,218,224,0.98)'
ctx.strokeStyle = 'rgba(54,58,64,0.96)'
ctx.lineWidth = 1.3
for(let i = 0; i < movingParticles; i += 1){
const lane = i % 2
const phaseRaw = (streamSpeed + i * 0.15) % 1.25
if(phaseRaw > 1) continue
const startX = left + 18 + (i % 3) * 10
const startY = sy + (-58 + (i % 4) * 32)
const slitY = lane === 0 ? slit1y : slit2y
const bandY = lane === 0 ? clusters[0] : clusters[1]
const spread = ((i * 13) % 5 - 2) * 4
let px = startX
let py = startY
if(phaseRaw < 0.56){
const t = phaseRaw / 0.56
px = startX + (barrierX - startX - 16) * t
py = startY * (1 - t) + slitY * t
}else{
const t = (phaseRaw - 0.56) / 0.44
px = barrierX + (detectorX - barrierX - 16) * t
py = slitY * (1 - t) + (bandY + spread) * t
}
ctx.beginPath()
ctx.arc(px, py, 4.4, 0, Math.PI * 2)
ctx.fill()
ctx.stroke()
}
ctx.restore()
}


function drawGlowBall(x, y, r, color){
ctx.save()
ctx.globalCompositeOperation = 'screen'
ctx.fillStyle = color
ctx.globalAlpha = 0.12
ctx.beginPath(); ctx.arc(x, y, r * 2.0, 0, Math.PI * 2); ctx.fill()
ctx.globalAlpha = 1
ctx.beginPath(); ctx.arc(x, y, r, 0, Math.PI * 2); ctx.fill()
ctx.fillStyle = 'rgba(255,255,255,0.32)'
ctx.beginPath(); ctx.arc(x - r * 0.28, y - r * 0.28, r * 0.34, 0, Math.PI * 2); ctx.fill()
ctx.restore()
}

function drawArrow(x1, y1, x2, y2, color, width = 3, head = 12){
const angle = Math.atan2(y2 - y1, x2 - x1)
ctx.save()
ctx.strokeStyle = color
ctx.fillStyle = color
ctx.lineWidth = width
ctx.beginPath(); ctx.moveTo(x1, y1); ctx.lineTo(x2, y2); ctx.stroke()
ctx.beginPath()
ctx.moveTo(x2, y2)
ctx.lineTo(x2 - Math.cos(angle - Math.PI / 6) * head, y2 - Math.sin(angle - Math.PI / 6) * head)
ctx.lineTo(x2 - Math.cos(angle + Math.PI / 6) * head, y2 - Math.sin(angle + Math.PI / 6) * head)
ctx.closePath()
ctx.fill()
ctx.restore()
}

function orbitalColorByType(type){
if(type === 's') return 'rgba(126,232,116,0.95)'
if(type === 'p') return 'rgba(76,124,255,0.95)'
if(type === 'd') return 'rgba(255,90,90,0.95)'
return 'rgba(220,224,232,0.95)'
}

function drawOrbitalGlyph(type, cx, cy, scale, color = orbitalColorByType(type), variant = 0, opts = {}){
const palette = {
 s:['rgba(0,194,224,0.86)','rgba(0,194,224,0.86)'],
 p:['rgba(255,73,56,0.86)','rgba(0,194,224,0.86)'],
 d:['rgba(255,73,56,0.86)','rgba(0,194,224,0.86)'],
 f:['rgba(255,73,56,0.86)','rgba(0,194,224,0.86)']
}[type] || [color, color]
const showAxes = opts.showAxes !== false
const labelAxes = opts.labelAxes !== false && scale >= 20
ctx.save()
ctx.translate(cx, cy)
const axisColor = 'rgba(28,34,44,0.55)'
const axisW = Math.max(1.2, scale * 0.045)
if(showAxes){
  ctx.strokeStyle = axisColor
  ctx.lineWidth = axisW
  ctx.beginPath()
  ctx.moveTo(-scale * 1.18, scale * 0.58)
  ctx.lineTo(scale * 1.18, -scale * 0.58)
  ctx.moveTo(-scale * 1.08, -scale * 0.68)
  ctx.lineTo(scale * 1.08, scale * 0.68)
  ctx.moveTo(0, scale * 1.22)
  ctx.lineTo(0, -scale * 1.22)
  ctx.stroke()
  function axisArrow(x1, y1, x2, y2){
    const ang = Math.atan2(y2 - y1, x2 - x1)
    const head = Math.max(4, scale * 0.14)
    ctx.beginPath()
    ctx.moveTo(x2, y2)
    ctx.lineTo(x2 - Math.cos(ang - Math.PI / 6) * head, y2 - Math.sin(ang - Math.PI / 6) * head)
    ctx.lineTo(x2 - Math.cos(ang + Math.PI / 6) * head, y2 - Math.sin(ang + Math.PI / 6) * head)
    ctx.closePath()
    ctx.fillStyle = axisColor
    ctx.fill()
  }
  axisArrow(-scale * 1.18, scale * 0.58, scale * 1.18, -scale * 0.58)
  axisArrow(-scale * 1.08, -scale * 0.68, scale * 1.08, scale * 0.68)
  axisArrow(0, scale * 1.22, 0, -scale * 1.22)
  if(labelAxes){
    ctx.fillStyle = 'rgba(22,28,40,0.86)'
    ctx.font = `${Math.max(10, scale * 0.34)}px Georgia, Times New Roman, serif`
    ctx.textAlign = 'center'
    ctx.textBaseline = 'middle'
    ctx.fillText('z', 0, -scale * 1.44)
    ctx.fillText('x', scale * 1.34, scale * 0.70)
    ctx.fillText('y', scale * 1.28, -scale * 0.78)
  }
}
function glossyLobe(px, py, rx, ry, rot, fill, alpha = 0.95){
  ctx.save()
  ctx.translate(px, py)
  ctx.rotate(rot)
  ctx.globalCompositeOperation = 'screen'
  ctx.fillStyle = fill
  ctx.globalAlpha = alpha * 0.24
  ctx.beginPath(); ctx.ellipse(0, 0, rx * 1.34, ry * 1.34, 0, 0, Math.PI * 2); ctx.fill()
  ctx.globalAlpha = alpha
  ctx.beginPath(); ctx.ellipse(0, 0, rx, ry, 0, 0, Math.PI * 2); ctx.fill()
  const hi = ctx.createRadialGradient(-rx * 0.22, -ry * 0.26, 0, 0, 0, Math.max(rx, ry))
  hi.addColorStop(0, 'rgba(255,255,255,0.34)')
  hi.addColorStop(1, 'rgba(255,255,255,0)')
  ctx.fillStyle = hi
  ctx.beginPath(); ctx.ellipse(0, 0, rx, ry, 0, 0, Math.PI * 2); ctx.fill()
  ctx.restore()
}
function ring(rx, ry, stroke){
  ctx.save()
  ctx.strokeStyle = stroke
  ctx.lineWidth = Math.max(1.4, scale * 0.08)
  ctx.beginPath(); ctx.ellipse(0, 0, rx, ry, 0, 0, Math.PI * 2); ctx.stroke()
  ctx.restore()
}
if(type === 's'){
  ctx.globalCompositeOperation = 'screen'
  ctx.fillStyle = palette[0]
  ctx.globalAlpha = 0.20
  ctx.beginPath(); ctx.arc(0, 0, scale * 0.96, 0, Math.PI * 2); ctx.fill()
  ctx.globalAlpha = 0.98
  ctx.beginPath(); ctx.arc(0, 0, scale * 0.66, 0, Math.PI * 2); ctx.fill()
  ctx.fillStyle = 'rgba(255,255,255,0.22)'
  ctx.beginPath(); ctx.arc(-scale * 0.16, -scale * 0.16, scale * 0.18, 0, Math.PI * 2); ctx.fill()
}else if(type === 'p'){
  const angles = [Math.PI * 0.62, Math.PI * 0.5, Math.PI * 0.12]
  const angle = angles[variant % angles.length]
  const dx = Math.cos(angle) * scale * 0.52
  const dy = Math.sin(angle) * scale * 0.52
  glossyLobe(-dx, -dy, scale * 0.34, scale * 0.64, angle, palette[0])
  glossyLobe(dx, dy, scale * 0.34, scale * 0.64, angle, palette[1])
}else if(type === 'd'){
  if(variant === 2){
    glossyLobe(0, -scale * 0.64, scale * 0.28, scale * 0.48, 0, palette[1])
    glossyLobe(0, scale * 0.64, scale * 0.28, scale * 0.48, 0, palette[1])
    glossyLobe(-scale * 0.38, 0, scale * 0.36, scale * 0.28, 0, palette[0], 0.88)
    glossyLobe(scale * 0.38, 0, scale * 0.36, scale * 0.28, 0, palette[0], 0.88)
    ring(scale * 0.46, scale * 0.16, 'rgba(255,128,160,0.42)')
  }else{
    const angles = [Math.PI * 0.26, Math.PI * 0.06, 0, Math.PI * 0.20, -Math.PI * 0.20]
    const base = angles[variant % angles.length]
    for(let i = 0; i < 4; i += 1){
      const a = base + i * Math.PI * 0.5
      glossyLobe(Math.cos(a) * scale * 0.56, Math.sin(a) * scale * 0.56, scale * 0.26, scale * 0.46, a, i % 2 === 0 ? palette[0] : palette[1])
    }
  }
}else if(type === 'f'){
  const modes = [
    {base:0.12, core:true},
    {base:0.30, core:false},
    {base:0.56, core:true},
    {base:0.76, core:false},
    {base:0.96, core:true},
    {base:1.18, core:false},
    {base:1.42, core:true}
  ]
  const mode = modes[variant % modes.length]
  for(let i = 0; i < 6; i += 1){
    const a = mode.base + i * Math.PI / 3
    glossyLobe(Math.cos(a) * scale * 0.58, Math.sin(a) * scale * 0.58, scale * 0.18, scale * 0.40, a, i % 2 === 0 ? palette[0] : palette[1], 0.94)
  }
  if(mode.core){
    glossyLobe(0, -scale * 0.18, scale * 0.16, scale * 0.34, 0, palette[1], 0.88)
    glossyLobe(0, scale * 0.18, scale * 0.16, scale * 0.34, 0, palette[0], 0.88)
  }
}
ctx.restore()
}



