  drawWrappedBoardText('Nesta etapa, o foco é só a leitura dos quatro subníveis: s, p, d e f. As orientações individuais ficam unidas em uma única estrutura para cada família orbital.', cardX + 24, cardY + 54, cardW - 48, 22, 14, textSoft, 500)
  const cols = 4
  const gap = 14
