  const lowerY = innerY + innerH * 0.66
  ctx.save(); ctx.strokeStyle='rgba(188,206,236,0.22)'; ctx.lineWidth=2.2; ctx.beginPath(); ctx.moveTo(upperX, upperY - 52); ctx.lineTo(lowerX, lowerY + 52); ctx.stroke(); ctx.restore()
  drawGlowBall(upperX, upperY, 24, 'rgba(248,190,55,0.98)')
  drawGlowBall(lowerX, lowerY, 24, 'rgba(248,190,55,0.98)')
  drawArrow(upperX + 12, upperY, upperX + 72, upperY, 'rgba(153,219,255,0.96)', 3, 12)
